import{_ as t,o,c as a,a4 as s}from"./chunks/framework.B43MrHbS.js";const h=JSON.parse('{"title":"Padroes de Componentes","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/guide/components.md","filePath":"pt-BR/guide/components.md"}'),i={name:"pt-BR/guide/components.md"};function n(r,e,d,l,p,c){return o(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="padroes-de-componentes" tabindex="-1">Padroes de Componentes <a class="header-anchor" href="#padroes-de-componentes" aria-label="Permalink to &quot;Padroes de Componentes&quot;">​</a></h1><p>Componentes sao a camada de UI. Eles compoem outros componentes, consomem dados da camada logica e lidam com interacoes do usuario. Estes padroes se aplicam a todos os frameworks.</p><h2 id="principios-universais" tabindex="-1">Principios Universais <a class="header-anchor" href="#principios-universais" aria-label="Permalink to &quot;Principios Universais&quot;">​</a></h2><ul><li><strong>Props entrada, eventos saida</strong> — componentes recebem dados via props e comunicam via eventos/callbacks</li><li><strong>Composicao sobre heranca</strong> — construa UIs complexas compondo componentes pequenos</li><li><strong>Componentes pequenos</strong> — mantenha abaixo de 200 linhas; decomponha quando maior</li><li><strong>Trate todos os estados</strong> — loading, error e empty devem ser cobertos</li><li><strong>Sem logica de negocio pesada</strong> — delegue para a camada logica (hooks, composables, services)</li></ul><h2 id="evite-prop-drilling" tabindex="-1">Evite Prop Drilling <a class="header-anchor" href="#evite-prop-drilling" aria-label="Permalink to &quot;Evite Prop Drilling&quot;">​</a></h2><p>Quando dados precisam passar por multiplos niveis de componentes, evite passar props por intermediarios.</p><p>Cada framework tem sua propria solucao:</p><table tabindex="0"><thead><tr><th>Framework</th><th>Composicao</th><th>Contexto compartilhado</th></tr></thead><tbody><tr><td>Vue</td><td>Slots</td><td>provide / inject</td></tr><tr><td>React</td><td>Children / render props</td><td>Context API</td></tr><tr><td>Next.js</td><td>Children / render props</td><td>Context API</td></tr><tr><td>SvelteKit</td><td>Slots / snippets</td><td>Context (getContext / setContext)</td></tr><tr><td>Angular</td><td>Content projection</td><td>Dependency injection</td></tr><tr><td>Nuxt</td><td>Slots</td><td>provide / inject</td></tr></tbody></table><p><strong>O principio e o mesmo em todos os frameworks:</strong></p><ol><li><strong>Composicao</strong> — deixe componentes pai injetar conteudo nos slots de layout dos filhos</li><li><strong>Contexto</strong> — compartilhe estado atraves de um provider com escopo em vez de passar props</li></ol><h2 id="hierarquia-de-componentes" tabindex="-1">Hierarquia de Componentes <a class="header-anchor" href="#hierarquia-de-componentes" aria-label="Permalink to &quot;Hierarquia de Componentes&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Views (Paginas)       → Composicao, orquestracao, fornecer contexto</span></span>
<span class="line"><span>  └── Layout          → Estrutura visual (slots / children)</span></span>
<span class="line"><span>      └── Features    → Logica de funcionalidade (hooks, composables, stores)</span></span>
<span class="line"><span>          └── Shared  → Apresentacao pura (props entrada, eventos saida)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Tipo</th><th>Responsabilidade</th><th>Pode ter logica?</th><th>Pode ter estado?</th></tr></thead><tbody><tr><td><strong>Views</strong></td><td>Compor componentes, fornecer contexto</td><td>Via camada logica</td><td>Sim (camada logica)</td></tr><tr><td><strong>Componentes de Feature</strong></td><td>UI + logica de funcionalidade</td><td>Via camada logica</td><td>Sim (camada logica)</td></tr><tr><td><strong>Componentes Compartilhados</strong></td><td>UI generica e reutilizavel</td><td>Minima (apenas UI)</td><td>Minimo (local)</td></tr></tbody></table><h2 id="limites-de-tamanho" tabindex="-1">Limites de Tamanho <a class="header-anchor" href="#limites-de-tamanho" aria-label="Permalink to &quot;Limites de Tamanho&quot;">​</a></h2><ul><li>Total do componente: <strong>&lt; 200 linhas</strong></li><li>Template / JSX: <strong>&lt; 100 linhas</strong></li><li>Se maior → decomponha em sub-componentes</li></ul><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>[ ] TypeScript com tipos estritos</li><li>[ ] Props tipadas</li><li>[ ] Eventos / outputs tipados</li><li>[ ] Sem prop drilling (use composicao ou contexto)</li><li>[ ] Estados de loading / error / vazio tratados</li><li>[ ] Sem logica de negocio no template / JSX</li><li>[ ] Sem injecao de HTML bruto sem sanitizacao</li></ul>`,17)])])}const u=t(i,[["render",n]]);export{h as __pageData,u as default};
